class Solution:
    def swimInWater(self, grid):
        n = len(grid)
        def reachable(t):
            if grid[0][0] > t:
                return False
            from collections import deque
            seen = [[False] * n for _ in range(n)]
            seen[0][0] = True
            q = deque([(0, 0)])
            while q:
                r, c = q.popleft()
                if r == n - 1 and c == n - 1:
                    return True
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < n and 0 <= nc < n and not seen[nr][nc] and grid[nr][nc] <= t:
                        seen[nr][nc] = True
                        q.append((nr, nc))
            return False
        lo, hi = 0, n * n - 1
        while lo < hi:
            mid = (lo + hi) // 2
            if reachable(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

